// Determine current quarter
const now = new Date();
const quarter = Math.ceil((now.getMonth() + 1) / 3);
const year = now.getFullYear();
const qStart = new Date(year, (quarter - 1) * 3 - 3, 1).toISOString().split('T')[0]; // Previous quarter start
const qEnd = new Date(year, (quarter - 1) * 3, 0).toISOString().split('T')[0]; // Previous quarter end

return [{ json: { quarter: `Q${quarter > 1 ? quarter - 1 : 4}`, year: quarter > 1 ? year : year - 1, q_start: qStart, q_end: qEnd } }];

// Step 1: Agent Performance Data
const ctx = $input.first().json;
const supaFetch = async (path) => {
  const resp = await fetch(`${$env.SUPABASE_URL}/rest/v1/${path}`, {
    headers: { 'apikey': $env.SUPABASE_SERVICE_ROLE_KEY, 'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}` },
    signal: AbortSignal.timeout(10000)
  });
  return resp.json();
};

// Agent logs for last quarter
const logs = await supaFetch(`agent_logs?created_at=gte.${ctx.q_start}&created_at=lte.${ctx.q_end}T23:59:59&select=*`);
const logArr = Array.isArray(logs) ? logs : [];

// Group by agent
const byAgent = {};
for (const log of logArr) {
  const name = log.agent_name || 'unknown';
  if (!byAgent[name]) byAgent[name] = { calls: 0, confidence_scores: [], validation: { pass: 0, correction: 0, fail: 0 }, escalated: 0, tokens: 0, cost: 0 };
  byAgent[name].calls++;
  if (log.confidence_score) byAgent[name].confidence_scores.push(log.confidence_score);
  if (log.validation_status === 'pass') byAgent[name].validation.pass++;
  else if (log.validation_status === 'correction') byAgent[name].validation.correction++;
  else if (log.validation_status === 'fail') byAgent[name].validation.fail++;
  if (log.escalated) byAgent[name].escalated++;
  byAgent[name].tokens += (parseInt(log.tokens_in) || 0) + (parseInt(log.tokens_out) || 0);
  byAgent[name].cost += parseFloat(log.cost_eur) || 0;
}

const agentStats = Object.entries(byAgent).map(([name, stats]) => ({
  agent: name,
  calls: stats.calls,
  avg_confidence: stats.confidence_scores.length > 0 ? stats.confidence_scores.filter(s => s === 'hoch').length / stats.confidence_scores.length : null,
  pass_rate: stats.calls > 0 ? Math.round(stats.validation.pass / stats.calls * 100) : 0,
  correction_rate: stats.calls > 0 ? Math.round(stats.validation.correction / stats.calls * 100) : 0,
  fail_rate: stats.calls > 0 ? Math.round(stats.validation.fail / stats.calls * 100) : 0,
  escalation_rate: stats.calls > 0 ? Math.round(stats.escalated / stats.calls * 100) : 0,
  avg_tokens: stats.calls > 0 ? Math.round(stats.tokens / stats.calls) : 0,
  total_cost: Math.round(stats.cost * 100) / 100
}));

// Step 2: User Feedback
const feedback = await supaFetch(`user_feedback?created_at=gte.${ctx.q_start}&created_at=lte.${ctx.q_end}T23:59:59&select=*`);
const fbArr = Array.isArray(feedback) ? feedback : [];
const fbByAgent = {};
for (const fb of fbArr) {
  const name = fb.agent_name || 'unknown';
  if (!fbByAgent[name]) fbByAgent[name] = { positive: 0, negative: 0, total: 0 };
  fbByAgent[name].total++;
  if (fb.rating === 'positive' || fb.rating === '👍') fbByAgent[name].positive++;
  else fbByAgent[name].negative++;
}

// Step 3: Coverage Gaps
const gaps = await supaFetch(`coverage_gaps?created_at=gte.${ctx.q_start}&created_at=lte.${ctx.q_end}T23:59:59&select=*`);
const gapArr = Array.isArray(gaps) ? gaps : [];
const gapTopics = {};
for (const g of gapArr) {
  const topic = g.topic || g.category || 'unknown';
  gapTopics[topic] = (gapTopics[topic] || 0) + 1;
}
const frequentGaps = Object.entries(gapTopics).filter(([_, count]) => count >= 3).map(([topic, count]) => ({ topic, count }));

// Step 4: Knowledge Staleness
const staleThresholds = { tax: 180, immigration: 180, default: 365 };
const sixMonthsAgo = new Date(Date.now() - 180*86400000).toISOString();
const oneYearAgo = new Date(Date.now() - 365*86400000).toISOString();
const staleChunks = await supaFetch(`knowledge_base?updated_at=lt.${sixMonthsAgo}&select=id,category,title,updated_at&order=updated_at.asc&limit=20`);
const staleArr = Array.isArray(staleChunks) ? staleChunks : [];

return [{ json: {
  ...ctx,
  agent_stats: agentStats,
  feedback_by_agent: fbByAgent,
  total_feedback: fbArr.length,
  coverage_gaps_total: gapArr.length,
  frequent_gaps: frequentGaps,
  stale_chunks: staleArr.length,
  stale_list: staleArr.slice(0, 10).map(c => `${c.category}/${c.title} (${c.updated_at?.split('T')[0]})`)
}}];

// Step 5: Telegram Report
const data = $input.first().json;

let msg = `📊 *Quarterly Quality Report ${data.quarter} ${data.year}*\n\n`;

// Agent Stats
if (data.agent_stats.length > 0) {
  const sorted = [...data.agent_stats].sort((a, b) => b.calls - a.calls);
  const topAgent = sorted[0];
  msg += `*Agents:* ${sorted.length} aktiv, ${sorted.reduce((s, a) => s + a.calls, 0)} Calls total\n`;
  msg += `Top: ${topAgent.agent} (${topAgent.calls} Calls, ${topAgent.pass_rate}% Pass)\n`;
  const totalCost = sorted.reduce((s, a) => s + a.total_cost, 0);
  msg += `Gesamtkosten: ${Math.round(totalCost * 100) / 100}€\n\n`;
} else {
  msg += `*Agents:* Keine Daten für dieses Quartal\n\n`;
}

// Feedback
msg += `*Feedback:* ${data.total_feedback} Bewertungen\n`;
for (const [agent, fb] of Object.entries(data.feedback_by_agent)) {
  const rate = fb.total > 0 ? Math.round(fb.positive / fb.total * 100) : 0;
  msg += `  ${agent}: ${rate}% positiv (${fb.total})\n`;
}
msg += '\n';

// Coverage Gaps
msg += `*Coverage Gaps:* ${data.coverage_gaps_total} total\n`;
if (data.frequent_gaps.length > 0) {
  msg += `Häufungen: ${data.frequent_gaps.map(g => `${g.topic} (${g.count}x)`).join(', ')}\n`;
}
msg += '\n';

// Stale Knowledge
msg += `*Veraltete Chunks:* ${data.stale_chunks}\n`;
if (data.stale_list.length > 0) {
  msg += data.stale_list.slice(0, 5).map(s => `  - ${s}`).join('\n') + '\n';
}
msg += '\n→ Review im Dashboard, Prompt-Anpassungen manuell in knowledge\\_base/core-prompts/ vornehmen';

// Truncate
if (msg.length > 4000) msg = msg.substring(0, 3997) + '...';

return [{ json: { message: msg, urgency: 'green', category: 'quarterly_quality' } }];

const data = $('Daten sammeln').first().json;
return [{ json: {
  session_id: `quarterly_quality_${data.quarter}_${data.year}`,
  agent_name: 'quarterly_quality',
  model: 'none',
  input_summary: `Quality Check ${data.quarter} ${data.year}`,
  output_summary: `${data.agent_stats?.length || 0} Agents, ${data.coverage_gaps_total} Gaps, ${data.stale_chunks} stale`,
  tokens_in: 0,
  tokens_out: 0
}}];
